mapper.insert:
INSERT INTO network_task (
  task_id, raw_text, description, task_status, current_stage, created_by, create_time, update_time
) VALUES (
  #{taskId}, #{rawText}, #{description}, #{taskStatus}, #{currentStage}, #{createdBy}, #{createTime}, #{updateTime}
)

mapper.select:
SELECT task_id, raw_text, description, task_status, current_stage, created_by, create_time, update_time
FROM network_task
WHERE task_id = #{taskId}
